parameters.jsCode:
const content = $json.choices?.[0]?.message?.content || '{}';
let a = {};
try { a = JSON.parse(content); } catch (e) {}
const id = $('Split Records').item.json.id;
const clean = (v) => (v === undefined || v === null) ? '' : v;
const types = Array.isArray(a.partnership_types) ? a.partnership_types : [];
const valid = ['Sponsorship','Strategic','Advertising','Influencer'];
return [{ json: {
  recordId: id,
  fields: {
    'Company Summary': clean(a.company_summary),
    'Opportunity Summary': clean(a.opportunity_summary),
    'Risk Assessment': clean(a.risk_assessment),
    'Recommended Approach': clean(a.recommended_approach),
    'Partnership Types': types.filter(t => valid.includes(t)),
    'Lead Score': Number(a.lead_score) || 0,
    'Classification': ['Hot','Warm','Cold'].includes(a.classification) ? a.classification : 'Cold',
    'Status': 'Analyzed'
  }
}}];
